html:
{% set student = frappe.get_doc("Student", doc.student) if doc.student else None %}
{% set student_group = frappe.get_doc("Student Group", doc.student_group) if doc.student_group else None %}
{% set group_instructor = student_group.instructors[0] if student_group and student_group.instructors else None %}
{% set instructor = frappe.get_doc("Instructor", group_instructor.instructor) if group_instructor and group_instructor.instructor else None %}

{# Get only the latest passed attempt linked with this Assessment Result #}
{% set quiz_activities = frappe.get_all(
    "Quiz Activity",
    filters={
        "custom_assesment_result": doc.name,
        "status": "Pass"
    },
    fields=[
        "name",
        "student",
        "custom_student_group",
        "custom_assesment_plan",
        "quiz",
        "status",
        "score",
        "activity_date",
        "creation"
    ],
    order_by="activity_date desc, creation desc",
    limit_page_length=1
) %}

{# Fallback if Quiz Activity is not directly linked with Assessment Result #}
{% if not quiz_activities %}
    {% set quiz_activities = frappe.get_all(
        "Quiz Activity",
        filters={
            "student": doc.student,
            "custom_student_group": doc.student_group,
            "custom_assesment_plan": doc.assessment_plan,
            "status": "Pass"
        },
        fields=[
            "name",
            "student",
            "custom_student_group",
            "custom_assesment_plan",
            "quiz",
            "status",
            "score",
            "activity_date",
            "creation"
        ],
        order_by="activity_date desc, creation desc",
        limit_page_length=1
    ) %}
{% endif %}

<style>
@page {
    size: A4;
    margin: 10mm 10mm 9mm;
}

.print-format {
    font-family: Arial, Helvetica, sans-serif;
    font-size: 10px;
    color: #333;
}

.theory-page {
    max-width: 190mm;
    margin: 0 auto;
}

.theory-header {
    display: table;
    width: 100%;
    margin-bottom: 8px;
}

.brand-left,
.brand-right,
.brand-title {
    display: table-cell;
    vertical-align: top;
}

.brand-left,
.brand-right {
    width: 23%;
}

.brand-right {
    text-align: right;
}

.brand-mark {
    color: #1f62ad;
    font-size: 22px;
    font-weight: 800;
    line-height: 1;
}

.brand-sub {
    color: #1f62ad;
    font-size: 10px;
    font-weight: 700;
    margin-top: 2px;
}

.adnoc-front {
    text-align: right;
}

.adnoc-front-img {
    max-width: 66px;
    max-height: 88px;
    object-fit: contain;
}

.title-main {
    margin-top: 22px;
    font-size: 20px;
    line-height: 1.1;
    font-weight: 800;
    color: #1f62ad;
    white-space: normal;
}

.title-main .orange-text {
    color: #eb7b3b;
}

.subtitle {
    color: #1f62ad;
    font-weight: 700;
    margin: 5px 0 8px;
    font-size: 12px;
}

.info-table,
.assessment-table,
.records-table,
.sign-table {
    width: 100%;
    border-collapse: collapse;
    table-layout: fixed;
}

.info-table td,
.assessment-table td,
.records-table td,
.records-table th,
.sign-table td,
.sign-table th {
    border: 1px solid #777;
    vertical-align: middle;
}

.info-label {
    background: #155fa8;
    color: #fff;
    font-weight: 700;
    padding: 6px;
    width: 20%;
}

.info-value {
    padding: 5px 8px;
    min-height: 18px;
}

.instruction {
    margin: 7px 0;
    font-size: 11px;
}

.unit-bar {
    background: #eb7b3b;
    color: #fff;
    font-weight: 800;
    padding: 5px 7px;
    border: 1px solid #eb7b3b;
}

.unit-cell {
    background: #155fa8;
    color: #fff;
    font-weight: 700;
    width: 18%;
    padding: 7px 6px;
    line-height: 1.2;
}

.question-cell {
    width: 31%;
    padding: 7px;
    line-height: 1.25;
}

.options-cell {
    width: 51%;
    padding: 6px 7px;
}

.option-row {
    display: table;
    width: 100%;
    line-height: 1.25;
    page-break-inside: avoid;
}

.option-text {
    display: table-cell;
    padding: 1px 5px 1px 0;
}

.box {
    display: table-cell;
    width: 15px;
    color: #1f62ad;
    font-size: 13px;
    line-height: 1;
    text-align: center;
}

.question-title {
    font-weight: 700;
    margin-bottom: 4px;
}

.result-note {
    color: #c73636;
    font-size: 9px;
    margin-top: 4px;
}

.summary-title {
    margin-top: 10px;
}

.records-table th,
.sign-table th {
    background: #eb7b3b;
    color: #fff;
    font-weight: 800;
    padding: 6px;
}

.records-table td,
.sign-table td {
    padding: 6px;
    height: 42px;
}

.signature-img {
    max-width: 120px;
    max-height: 38px;
    object-fit: contain;
}

.declaration-section {
    margin: 8px 0 6px;
    font-size: 10px;
    line-height: 1.25;
}

.declaration-section p {
    margin: 2px 0;
}

.center {
    text-align: center;
}

.footer-company {
    margin-top: 7px;
    text-align: right;
    color: #1f62ad;
    font-weight: 800;
    border-top: 2px solid #1f62ad;
    padding-top: 4px;
}

.avoid-break {
    page-break-inside: avoid;
}
</style>

<div class="theory-page">

    <div class="theory-header">
        <div class="brand-left">
            <div class="brand-mark">
                100%<br>HSE
            </div>
        </div>

        <div class="brand-title">
            <div class="title-main">
                <span class="orange-text">THEORY ASSESSMENT</span>
                - {{ doc.course or "ASSESSMENT" }}
            </div>
        </div>

        <div class="brand-right">
            <div class="adnoc-front">
                <img src="/files/adnoc.png" class="adnoc-front-img">
            </div>
        </div>
    </div>

    <div class="subtitle">
        {{ doc.course or doc.assessment_plan or "Theory Assessment" }} form
    </div>

    <table class="info-table">
        <tr>
            <td class="info-label">Candidate Name</td>

            <td class="info-value">
                {{ doc.student_name or
                   (student.student_name if student else "") or
                   doc.student or "" }}
            </td>

            <td class="info-label">Date</td>

            <td class="info-value">
                {{ frappe.utils.formatdate(
                    doc.course_start_date or
                    doc.date or
                    (student_group.from_date if student_group else None) or
                    (student_group.custom_from_date if student_group else None)
                ) }}
            </td>
        </tr>

        <tr>
            <td class="info-label">Employing company</td>

            <td class="info-value">
                {{ doc.customer_name or
                   doc.custom_company or
                   (student.custom_candidate_company_name if student else "") or
                   (student.custom_student_company_name if student else "") or
                   (student.customer_name if student else "") or
                   (student_group.custom_customer if student_group else "") or
                   "" }}
            </td>

            <td class="info-label">Mobile number</td>

            <td class="info-value">
                {% if student %}
                    {{ student.student_mobile_number or student.custom_phone or "" }}
                {% endif %}
            </td>
        </tr>

        <tr>
            <td class="info-label">Student Group</td>

            <td class="info-value">
                {{ doc.student_group or "" }}
            </td>

            <td class="info-label">Result</td>

            <td class="info-value">
                {% if quiz_activities %}
                    {{ quiz_activities[0].status or "" }}
                {% else %}
                    {{ doc.grade or doc.total_score or "" }}
                {% endif %}
            </td>
        </tr>
    </table>

    <div class="instruction">
        Use black biro pen to mark X in the correct box(s)
    </div>

    {% for activity in quiz_activities %}

        {% set quiz_doc = frappe.get_doc("Quiz", activity.quiz) if activity.quiz else None %}
        {% set qa_doc = frappe.get_doc("Quiz Activity", activity.name) %}

        <div class="unit-bar">
            UNIT {{ loop.index }} -
            {{ activity.quiz or doc.course or "Theory Assessment" }}
        </div>

        <table class="assessment-table">

            {% for result in qa_doc.result %}

                {% set question_doc = frappe.get_doc(
                    "Question",
                    result.question
                ) if result.question else None %}

                <tr class="avoid-break">

                    {% if loop.first %}
                        <td
                            class="unit-cell"
                            rowspan="{{ qa_doc.result|length }}"
                        >
                            {{ quiz_doc.title if quiz_doc else activity.quiz }}

                            <br><br>

                            Status: {{ activity.status or "" }}

                            <br>

                            Score: {{ activity.score or "" }}
                        </td>
                    {% endif %}

                    <td class="question-cell">
                        <div class="question-title">
                            {{ frappe.utils.strip_html(
                                question_doc.question
                                if question_doc
                                else result.question or ""
                            ) }}
                        </div>

                        <div>
                            Select the correct answer{% if question_doc and question_doc.question_type == "Multiple Correct Answer" %}(s){% endif %}
                        </div>
                    </td>

                    <td class="options-cell">

                        {% if question_doc and question_doc.options %}

                            {% for option in question_doc.options %}

                                {% set option_text = frappe.utils.strip_html(
                                    option.option or ""
                                ) %}

                                {% set selected =
                                    (result.selected_option or "") == (option.option or "")
                                    or
                                    (result.selected_option or "") == option_text
                                %}

                                <div class="option-row">
                                    <span class="option-text">
                                        {{ option_text }}
                                    </span>

                                    <span class="box">
                                        {% if selected %}
                                            ☑
                                        {% else %}
                                            ☐
                                        {% endif %}
                                    </span>
                                </div>

                            {% endfor %}

                        {% else %}

                            <div class="option-row">
                                <span class="option-text">
                                    {{ result.selected_option or "" }}
                                </span>

                                <span class="box">
                                    {% if result.selected_option %}
                                        ☑
                                    {% else %}
                                        ☐
                                    {% endif %}
                                </span>
                            </div>

                        {% endif %}

                        <div class="result-note">
                            Answer: {{ result.quiz_result or "" }}
                        </div>

                    </td>
                </tr>

            {% endfor %}

        </table>

    {% endfor %}

    {% if not quiz_activities %}

        <div class="unit-bar">
            ASSESSMENT QUESTIONS
        </div>

        <table class="assessment-table">
            <tr>
                <td class="question-cell">
                    No passed Quiz Activity was found for this Assessment Result.
                </td>

                <td class="options-cell">
                    Please verify the Quiz Activity status and Assessment Result link.
                </td>
            </tr>
        </table>

    {% endif %}

    <div class="unit-bar summary-title">
        CANDIDATE'S RECORDS
    </div>

    <table class="records-table">
        <tr>
            <th>Quiz</th>
            <th style="width:16%;">Status</th>
            <th style="width:16%;">Score</th>
            <th style="width:20%;">Source of Evidence</th>
        </tr>

        {% if quiz_activities %}

            {% set latest_activity = quiz_activities[0] %}

            <tr>
                <td>
                    {{ latest_activity.quiz or "" }}
                </td>

                <td class="center">
                    {{ latest_activity.status or "" }}
                </td>

                <td class="center">
                    {{ latest_activity.score or "" }}
                </td>

                <td class="center">
                    Q
                </td>
            </tr>

        {% else %}

            <tr>
                <td colspan="4" class="center">
                    No passed attempt found
                </td>
            </tr>

        {% endif %}
    </table>

    <p>
        <b>Learner Name:</b>
        {{ doc.student_name or
           (student.student_name if student else "") or
           doc.student or "" }}
    </p>

    <p>
        <b>Training and Development Needs:</b>
        {{ doc.comment or "" }}
    </p>

    <div class="declaration-section">
        <p>
            Declaration: The person named was assessed by me against the
            standards of performance specified in this document and in
            accordance with the assessment guidance.
        </p>

        <p>
            I consider that the above person has achieved a sufficient level
            of understanding of the Light Vehicle Professional Driving Theory
            course.
        </p>

        <p>
            *I consider that the above person requires further training and
            development in addition to that which is installation specific.
        </p>
    </div>

    <table class="sign-table">
        <tr>
            <th>Assessor's Name</th>
            <th>Signature</th>
            <th>Date</th>
        </tr>

        <tr>
            <td>
                {{ instructor.instructor_name
                   if instructor
                   else (
                       group_instructor.instructor_name
                       if group_instructor
                       else frappe.session.user
                   ) }}
            </td>

            <td class="center">
                {% if instructor and instructor.image %}
                    <img
                        src="{{ instructor.image }}"
                        class="signature-img"
                    >
                {% endif %}
            </td>

            <td>
                {{ frappe.utils.formatdate(
                    doc.course_end_date or
                    doc.course_start_date or
                    doc.date
                ) }}
            </td>
        </tr>
    </table>

    <div class="footer-company">
        Abu Dhabi National Oil Company
    </div>

</div>
